QueryExtension.Constraint:
(
	${param.owningCourtCode} IS NULL OR CO.ADMIN_COURT_CODE = ${param.owningCourtCode}
) 
AND
(
	${param.coNumber} IS NULL OR CO.CO_NUMBER = ${param.coNumber}
) 
AND																									
(
	${param.oldCoNumber} IS NULL OR CO.OLD_NUMBER = ${param.oldCoNumber}
)
